import{_ as a,o,c as l,ae as i}from"./chunks/framework.C7FLYIpo.js";const m=JSON.parse('{"title":"macOS IPC","description":"OpenClaw 앱, 게이트웨이 노드 전송, PeekabooBridge를 위한 macOS IPC 아키텍처","frontmatter":{"title":"macOS IPC","description":"OpenClaw 앱, 게이트웨이 노드 전송, PeekabooBridge를 위한 macOS IPC 아키텍처"},"headers":[],"relativePath":"platforms/mac/xpc.md","filePath":"platforms/mac/xpc.md","lastUpdated":null}'),t={name:"platforms/mac/xpc.md"};function c(n,e,s,r,d,p){return o(),l("div",null,[...e[0]||(e[0]=[i(`<h1 id="openclaw-macos-ipc-아키텍처" tabindex="-1">OpenClaw macOS IPC 아키텍처 <a class="header-anchor" href="#openclaw-macos-ipc-아키텍처" aria-label="Permalink to &quot;OpenClaw macOS IPC 아키텍처&quot;">​</a></h1><p><strong>현재 모델:</strong> 로컬 Unix 소켓이 <strong>노드 호스트 서비스</strong>와 <strong>macOS 앱</strong>을 exec 승인 + <code>system.run</code>으로 연결합니다. 검색/연결 확인을 위한 <code>openclaw-mac</code> 디버그 CLI가 있습니다. 에이전트 작업은 여전히 게이트웨이 WebSocket과 <code>node.invoke</code>를 통해 흐릅니다. UI 자동화는 PeekabooBridge를 사용합니다.</p><h2 id="목표" tabindex="-1">목표 <a class="header-anchor" href="#목표" aria-label="Permalink to &quot;목표&quot;">​</a></h2><ul><li>모든 TCC 대면 작업 (알림, 화면 녹화, 마이크, 음성, AppleScript)을 소유하는 단일 GUI 앱 인스턴스.</li><li>자동화를 위한 작은 표면: 게이트웨이 + 노드 명령, UI 자동화를 위한 PeekabooBridge.</li><li>예측 가능한 권한: 항상 동일한 서명된 번들 ID, launchd에서 시작되므로 TCC 부여가 유지됩니다.</li></ul><h2 id="작동-방식" tabindex="-1">작동 방식 <a class="header-anchor" href="#작동-방식" aria-label="Permalink to &quot;작동 방식&quot;">​</a></h2><h3 id="게이트웨이-노드-전송" tabindex="-1">게이트웨이 + 노드 전송 <a class="header-anchor" href="#게이트웨이-노드-전송" aria-label="Permalink to &quot;게이트웨이 + 노드 전송&quot;">​</a></h3><ul><li>앱이 게이트웨이를 실행하고 (로컬 모드) 노드로 연결합니다.</li><li>에이전트 작업은 <code>node.invoke</code>를 통해 수행됩니다 (예: <code>system.run</code>, <code>system.notify</code>, <code>canvas.*</code>).</li></ul><h3 id="노드-서비스-앱-ipc" tabindex="-1">노드 서비스 + 앱 IPC <a class="header-anchor" href="#노드-서비스-앱-ipc" aria-label="Permalink to &quot;노드 서비스 + 앱 IPC&quot;">​</a></h3><ul><li>헤드리스 노드 호스트 서비스가 게이트웨이 WebSocket에 연결합니다.</li><li><code>system.run</code> 요청은 로컬 Unix 소켓을 통해 macOS 앱으로 전달됩니다.</li><li>앱은 UI 컨텍스트에서 exec를 수행하고 필요한 경우 프롬프트를 표시하며 출력을 반환합니다.</li></ul><p>다이어그램 (SCI):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent -&gt; Gateway -&gt; Node Service (WS)</span></span>
<span class="line"><span>                      |  IPC (UDS + token + HMAC + TTL)</span></span>
<span class="line"><span>                      v</span></span>
<span class="line"><span>                  Mac App (UI + TCC + system.run)</span></span></code></pre></div><h3 id="peekaboobridge-ui-자동화" tabindex="-1">PeekabooBridge (UI 자동화) <a class="header-anchor" href="#peekaboobridge-ui-자동화" aria-label="Permalink to &quot;PeekabooBridge (UI 자동화)&quot;">​</a></h3><ul><li>UI 자동화는 별도의 <code>bridge.sock</code>이라는 UNIX 소켓과 PeekabooBridge JSON 프로토콜을 사용합니다.</li><li>호스트 선호 순서 (클라이언트 측): Peekaboo.app → Claude.app → OpenClaw.app → 로컬 실행.</li><li>보안: 브리지 호스트는 허용된 TeamID가 필요합니다. DEBUG 전용 동일-UID 탈출 해치는 <code>PEEKABOO_ALLOW_UNSIGNED_SOCKET_CLIENTS=1</code> (Peekaboo 관례)로 보호됩니다.</li><li>참조: 세부 사항은 <a href="/openclaw-docs-ko/platforms/mac/peekaboo">PeekabooBridge 사용</a>.</li></ul><h2 id="운영-흐름" tabindex="-1">운영 흐름 <a class="header-anchor" href="#운영-흐름" aria-label="Permalink to &quot;운영 흐름&quot;">​</a></h2><ul><li>재시작/재빌드: <code>SIGN_IDENTITY=&quot;Apple Development: &amp;lt;Developer Name&amp;gt; (&amp;lt;TEAMID&amp;gt;)&quot; scripts/restart-mac.sh</code><ul><li>기존 인스턴스 종료</li><li>Swift 빌드 + 패키지</li><li>LaunchAgent 쓰기/부트스트랩/킥스타트</li></ul></li><li>단일 인스턴스: 동일한 번들 ID를 가진 다른 인스턴스가 실행 중이면 앱이 일찍 종료됩니다.</li></ul><h2 id="강화-참고-사항" tabindex="-1">강화 참고 사항 <a class="header-anchor" href="#강화-참고-사항" aria-label="Permalink to &quot;강화 참고 사항&quot;">​</a></h2><ul><li>모든 권한 있는 표면에 TeamID 일치를 요구하는 것을 선호합니다.</li><li>PeekabooBridge: <code>PEEKABOO_ALLOW_UNSIGNED_SOCKET_CLIENTS=1</code> (DEBUG 전용)은 로컬 개발을 위해 동일-UID 호출자를 허용할 수 있습니다.</li><li>모든 통신은 로컬 전용으로 유지됩니다. 네트워크 소켓은 노출되지 않습니다.</li><li>TCC 프롬프트는 GUI 앱 번들에서만 발생합니다. 서명된 번들 ID를 재빌드 전반에 걸쳐 안정적으로 유지하십시오.</li><li>IPC 강화: 소켓 모드 <code>0600</code>, 토큰, 피어-UID 확인, HMAC 챌린지/응답, 짧은 TTL.</li></ul>`,17)])])}const u=a(t,[["render",c]]);export{m as __pageData,u as default};
